+  const table = extractTableName(stmt.from);
+  const filters: FilterOp[] = [];
+  const aggregates: AggregateOp[] = [];
+  const windows: WindowSpec[] = [];
+  let projections: string[] = [];
+  const computedExprs: { alias: string; expr: SqlExpr }[] = [];
